// ==============================================================
// Cancelar convocacao - validar, preparar updates e ler ledger
// ==============================================================

const BOARD_ENTRADA = 18408773953;
const BOARD_HISTORICO = 18411141462;

const COL_CONTRATO = 'text_mm2x1ktb';
const COL_CHAPA = 'text_mm33v9kp';
const COL_DATA_INICIO = 'date_mm2xtp93';
const COL_DATA_FIM = 'date_mm2xrr5q';
const COL_ITEM_ORIGEM = 'link_mm2x1rk0';
const COL_OPTANTE_VT = 'color_mm34ry47';
const COL_TRABALHA_SAB = 'color_mm34yyet';
const COL_STATUS_CANCEL_HIST = 'color_mm3b9v4n';
const COL_BENEF_LEDGER = 'long_text_mm3ct3hg';

const COL_ENTRADA_STATUS = 'color_mm3a8ana';
const COL_ENTRADA_DATA_CANCEL = 'date_mm3b88ta';

const webhook = $('Webhook').first().json;
const body = webhook.body || {};
const uuid = webhook.query?.uuid || body.uuid;
const tipo = String(body.tipo || '').trim();
const dataCancel = body.data_inicio_cancelamento || null;

function fail(code, erro, mensagem) { return [{ json: { _statusCode: code, erro, mensagem, ok: false } }]; }
function firstRealItem() {
  for (const it of $input.all()) {
    const j = it.json;
    if (j && j.id && (j.column_values || j.name)) return j;
  }
  return null;
}
function getText(cols, id) { return cols.find(c => c.id === id)?.text || null; }
function getRaw(cols, id) { return cols.find(c => c.id === id)?.value || null; }
function norm(v) { return String(v || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase().trim(); }
function parseJsonText(cols, id, fallback) {
  const text = getText(cols, id);
  if (!text) return fallback;
  try { return JSON.parse(text); } catch { return fallback; }
}
function parseItemOrigemId(cols) {
  const text = getText(cols, COL_ITEM_ORIGEM) || '';
  const raw = getRaw(cols, COL_ITEM_ORIGEM);
  let url = text;
  if (!url && raw) {
    try { const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw; url = parsed?.url || ''; } catch { url = ''; }
  }
  const m = String(url).match(/pulses\/(\d+)/);
  return m ? m[1] : null;
}
function dateValue(iso) { return iso ? { date: iso } : null; }
function dateRange(start, end, trabalhaSabado) {
  const out = [];
  const cur = new Date(start + 'T00:00:00Z');
  const fim = new Date(end + 'T00:00:00Z');
  while (cur <= fim) {
    const dow = cur.getUTCDay();
    if (dow !== 0 && (dow !== 6 || trabalhaSabado)) out.push(cur.toISOString().slice(0, 10));
    cur.setUTCDate(cur.getUTCDate() + 1);
  }
  return out;
}

if (!uuid) return fail(400, 'uuid_ausente', 'UUID ausente.');
if (tipo !== 'total' && tipo !== 'parcial') return fail(400, 'tipo_invalido', 'Tipo de cancelamento invalido.');
if (tipo === 'parcial' && !/^\d{4}-\d{2}-\d{2}$/.test(String(dataCancel || ''))) return fail(400, 'data_cancelamento_invalida', 'Informe a data de inicio do cancelamento parcial.');

const item = firstRealItem();
if (!item) return fail(404, 'nao_encontrado', 'Processamento nao encontrado.');

const cols = item.column_values || [];
const dataInicio = getText(cols, COL_DATA_INICIO);
const dataFim = getText(cols, COL_DATA_FIM);
const statusCancelAtual = norm(getText(cols, COL_STATUS_CANCEL_HIST));
const itemOrigemId = parseItemOrigemId(cols);
const trabalhaSabado = norm(getText(cols, COL_TRABALHA_SAB)) === 'SIM';
const beneficiosDescontados = parseJsonText(cols, COL_BENEF_LEDGER, {});

if (statusCancelAtual === 'CANCELADA' || statusCancelAtual === 'CANCELADA PARCIALMENTE') return fail(409, 'convocacao_ja_cancelada', 'Esta convocacao ja possui cancelamento registrado.');
if (!dataInicio || !dataFim) return fail(400, 'periodo_invalido', 'Convocacao sem data de inicio ou fim.');
if (!itemOrigemId) return fail(400, 'item_origem_ausente', 'Nao foi possivel localizar o item origem da convocacao.');
if (tipo === 'parcial' && (dataCancel < dataInicio || dataCancel > dataFim)) return fail(400, 'data_fora_periodo', 'A data de cancelamento precisa estar dentro do periodo da convocacao.');

const dataDescontoInicio = tipo === 'total' ? dataInicio : dataCancel;
const dataDescontoFim = dataFim;
const diasCancelados = dateRange(dataDescontoInicio, dataDescontoFim, trabalhaSabado);
const labelCancel = tipo === 'total' ? 'Cancelada' : 'Cancelada parcialmente';

const updateEntrada = { [COL_ENTRADA_STATUS]: { label: labelCancel } };
if (tipo === 'parcial') updateEntrada[COL_ENTRADA_DATA_CANCEL] = dateValue(dataCancel);

return [{ json: {
  ok: true,
  _statusCode: 200,
  uuid,
  tipo,
  item_id_historico: String(item.id),
  item_origem_id: itemOrigemId,
  nome: item.name,
  contrato: getText(cols, COL_CONTRATO) || '',
  chapa: getText(cols, COL_CHAPA) || '',
  data_inicio: dataInicio,
  data_fim: dataFim,
  data_inicio_cancelamento: tipo === 'parcial' ? dataCancel : null,
  data_desconto_inicio: dataDescontoInicio,
  data_desconto_fim: dataDescontoFim,
  dias_cancelados: diasCancelados,
  beneficios_descontados: beneficiosDescontados && typeof beneficiosDescontados === 'object' ? beneficiosDescontados : {},
  optante_vt: getText(cols, COL_OPTANTE_VT) || 'NAO',
  trabalha_sabado: trabalhaSabado ? 'SIM' : 'NAO',
  label_cancelamento: labelCancel,
  column_values_entrada_json: JSON.stringify(updateEntrada),
  boards: { entrada: BOARD_ENTRADA, historico: BOARD_HISTORICO }
} }];

// ==============================================================
// Cancelamento - criar/atualizar desconto respeitando ledger
// ==============================================================

const BOARD_DESCONTOS = 18400981023;
const GROUP_DESCONTOS = 'group_mm0rmjs3';
const COL_STATUS_CANCEL_HIST = 'color_mm3b9v4n';
const COL_BENEF_LEDGER = 'long_text_mm3ct3hg';

const COL_D_NOME = 'dropdown_mm0rgfrx';
const COL_D_MATRICULA = 'text_mm0rpqxs';
const COL_D_CPF = 'text_mm0r5ted';
const COL_D_DATA_INICIO = 'date_mm0r6tyr';
const COL_D_DATA_FIM = 'date_mm0rzpyv';
const COL_D_DIAS_PERDE_VT = 'numeric_mm3428yj';
const COL_D_DIAS_PERDE_VR = 'numeric_mm34p6p7';
const COL_D_QTD_ATRASOS = 'numeric_mm2pj1av';
const COL_D_DESCONTO_VR = 'numeric_mm0rgsaw';
const COL_D_DESCONTO_VT = 'numeric_mm0r5tca';
const COL_D_STATUS = 'color_mm0r8mjr';
const COL_D_RESIDUAL_VR = 'numeric_mm0r1691';
const COL_D_RESIDUAL_VT = 'numeric_mm0rtwwg';
const COL_D_DESCONTADO_VR = 'numeric_mm0rqy6z';
const COL_D_DESCONTADO_VT = 'numeric_mm0r6cn0';

const prep = $('Preparar cancelamento').first().json;
const origemRaw = $('Get Item Origem').first().json;
const origemItem = origemRaw?.data?.item ?? origemRaw?.item ?? origemRaw;
const origemColumns = origemItem?.column_values ?? [];
const origemGet = (id) => origemColumns.find(c => c.id === id)?.text ?? null;
const nomeNorm = (s) => String(s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toUpperCase().trim();

const chapa = String(prep.chapa || '').trim();
const cpf = String(origemGet('dup__of_matr_cula') || '').trim();
const funcao = nomeNorm(origemGet('texto0'));
const contrato = nomeNorm(prep.contrato);
const optanteVtRaw = nomeNorm(origemGet('optante___vt') || prep.optante_vt);
const optanteVT = optanteVtRaw === 'SIM' || optanteVtRaw === 'SIM*';
const vtSoVolta = optanteVtRaw === 'SIM*';
const trabalhaSabado = String(prep.trabalha_sabado || '').toUpperCase() === 'SIM';

let vrDia = 0;
let vtDia = 0;
let regraAplicada = '';
if (contrato === 'DETRAN') {
  if (funcao.includes('PORTARIA')) { vrDia = 514.50 / 30; regraAplicada = 'DETRAN - Agente de Portaria'; }
  else if (funcao.includes('MOTO BOY')) { vrDia = 27.00; regraAplicada = 'DETRAN - Moto Boy'; }
  else { vrDia = 588.00 / 30; regraAplicada = 'DETRAN - Outras Funcoes (' + funcao + ')'; }
  vtDia = 10.00;
} else if (contrato === 'TRE PB') {
  vrDia = 660.00 / 30;
  vtDia = 10.40;
  regraAplicada = 'TRE PB';
} else {
  vrDia = 24.50;
  vtDia = 10.00;
  regraAplicada = 'Padrao (' + contrato + ')';
}
if (!optanteVT) vtDia = 0;
if (vtSoVolta && vtDia > 0) { vtDia = vtDia / 2; regraAplicada += ' + VT so volta (1/2)'; }
vrDia = Math.round(vrDia * 100) / 100;
vtDia = Math.round(vtDia * 100) / 100;

function dow(d) { return new Date(d + 'T00:00:00Z').getUTCDay(); }
function isSabado(d) { return dow(d) === 6; }
function isDomingo(d) { return dow(d) === 0; }
function clone(v) { return JSON.parse(JSON.stringify(v || {})); }
function ensureLedger(ledger, d) {
  if (!ledger[d] || typeof ledger[d] !== 'object') ledger[d] = { vr: false, vt: false, origens: [] };
  if (!Array.isArray(ledger[d].origens)) ledger[d].origens = [];
  return ledger[d];
}
function percentualDescontado(ledger, d, benefit) {
  const e = ensureLedger(ledger, d);
  const key = benefit + '_percentual';
  const explicit = Number(e[key]);
  if (Number.isFinite(explicit) && explicit > 0) return Math.min(1, explicit);
  return e[benefit] === true ? 1 : 0;
}
function marcarPercentual(ledger, d, benefit, percentual, origem) {
  const e = ensureLedger(ledger, d);
  const key = benefit + '_percentual';
  const atual = percentualDescontado(ledger, d, benefit);
  const novo = Math.min(1, atual + Math.max(0, Number(percentual) || 0));
  e[benefit] = novo > 0;
  e[key] = novo;
  if (!e.origens.includes(origem)) e.origens.push(origem);
}

const ledger = clone(prep.beneficios_descontados);
const origemCancelamento = 'cancelamento:' + prep.tipo;
const diasIgnoradosDuplicidade = [];
let diasPerdeVT = 0;
let diasPerdeVR = 0;
let descontoVR = 0;
let descontoVT = 0;

for (const d of prep.dias_cancelados || []) {
  if (isDomingo(d)) continue;
  if (!trabalhaSabado && isSabado(d)) continue;

  if (!isSabado(d)) {
    const vrJaDescontado = percentualDescontado(ledger, d, 'vr');
    const vrFaltante = Math.max(0, 1 - vrJaDescontado);
    if (vrFaltante > 0) {
      diasPerdeVR += vrFaltante;
      descontoVR += vrDia * vrFaltante;
      marcarPercentual(ledger, d, 'vr', vrFaltante, origemCancelamento);
    } else {
      diasIgnoradosDuplicidade.push({ data: d, beneficio: 'vr' });
    }
  }

  if (optanteVT) {
    const vtJaDescontado = percentualDescontado(ledger, d, 'vt');
    const vtFaltante = Math.max(0, 1 - vtJaDescontado);
    if (vtFaltante > 0) {
      diasPerdeVT += vtFaltante;
      descontoVT += vtDia * vtFaltante;
      marcarPercentual(ledger, d, 'vt', vtFaltante, origemCancelamento);
    } else {
      diasIgnoradosDuplicidade.push({ data: d, beneficio: 'vt' });
    }
  }
}

if (!optanteVT) descontoVT = 0;
descontoVR = Math.round(descontoVR * 100) / 100;
descontoVT = Math.round(descontoVT * 100) / 100;

const descontosRaw = $input.all();
const descontosList = [];
for (const it of descontosRaw) {
  const j = it.json;
  if (!j || !j.id || !j.column_values) continue;
  const cols = {};
  for (const c of j.column_values) cols[c.id] = { text: c.text, value: c.value };
  const di = cols[COL_D_DATA_INICIO]?.text || null;
  const df = cols[COL_D_DATA_FIM]?.text || null;
  if (di === prep.data_desconto_inicio && df === prep.data_desconto_fim) descontosList.push({ id: String(j.id), status: nomeNorm(cols[COL_D_STATUS]?.text) });
}
const existente = descontosList[0] || null;
if (existente && (existente.status === 'PARCIAL' || existente.status === 'FINALIZADO')) {
  return [{ json: { _statusCode: 409, erro: 'desconto_em_consumo', mensagem: 'Nao e possivel cancelar: o desconto desta convocacao ja foi parcial ou totalmente consumido.', acao: 'skip' } }];
}

function toDate(d) { return d ? { date: d } : null; }
const columnValuesHistorico = {
  [COL_STATUS_CANCEL_HIST]: { label: prep.label_cancelamento },
  [COL_BENEF_LEDGER]: { text: JSON.stringify(ledger) }
};

const columnValues = {
  [COL_D_NOME]: { labels: [prep.nome] },
  [COL_D_MATRICULA]: chapa,
  [COL_D_CPF]: cpf,
  [COL_D_DATA_INICIO]: toDate(prep.data_desconto_inicio),
  [COL_D_DATA_FIM]: toDate(prep.data_desconto_fim),
  [COL_D_DIAS_PERDE_VT]: String(diasPerdeVT),
  [COL_D_DIAS_PERDE_VR]: String(diasPerdeVR),
  [COL_D_QTD_ATRASOS]: '0',
  [COL_D_DESCONTO_VR]: String(descontoVR),
  [COL_D_DESCONTO_VT]: String(descontoVT),
  [COL_D_STATUS]: { label: 'PENDENTE' },
  [COL_D_RESIDUAL_VR]: String(descontoVR),
  [COL_D_RESIDUAL_VT]: String(descontoVT),
  [COL_D_DESCONTADO_VR]: '0',
  [COL_D_DESCONTADO_VT]: '0'
};
for (const k of Object.keys(columnValues)) if (columnValues[k] === null || columnValues[k] === undefined) delete columnValues[k];

const acao = descontoVR === 0 && descontoVT === 0 ? 'skip' : (existente ? 'update' : 'create');
const columnValuesJson = JSON.stringify(columnValues);
const columnValuesEscaped = JSON.stringify(columnValuesJson);
let query = null;
if (acao === 'create') query = 'mutation { create_item(board_id: ' + BOARD_DESCONTOS + ', group_id: "' + GROUP_DESCONTOS + '", item_name: "INTERMITENTE", column_values: ' + columnValuesEscaped + ', create_labels_if_missing: true) { id } }';
else if (acao === 'update') query = 'mutation { change_multiple_column_values(board_id: ' + BOARD_DESCONTOS + ', item_id: ' + existente.id + ', column_values: ' + columnValuesEscaped + ', create_labels_if_missing: true) { id } }';

return [{ json: {
  _statusCode: 200,
  acao,
  item_id_desconto: existente?.id || null,
  query,
  descontoVR,
  descontoVT,
  dias_perde_vt: diasPerdeVT,
  dias_perde_vr: diasPerdeVR,
  dias_ignorados_duplicidade: diasIgnoradosDuplicidade,
  beneficios_descontados: ledger,
  column_values_historico_json: JSON.stringify(columnValuesHistorico),
  regraAplicada,
  vrDia,
  vtDia
} }];
